 886→    func navigateNext(amount: Int = 1) {
 887→        guard let folder else { return }
 888→        guard navigationThrottle.shouldProceed() else { return }
 889→        lastPrefetchDirection = .forward
 890→        if settings.dualPageEnabled {
 891→            guard amount == 1 else { return }  // Option+arrow jump 僅單頁模式
 892→            guard folder.goNextSpread() else { return }
 893→        } else {
 894→            guard folder.goNext(amount: amount) else { return }
 895→        }
 896→        loadCurrentImage(initialScroll: .top, thumbnailOnly: settings.thumbnailFallback)
 897→        if settings.thumbnailFallback { scheduleFullResLoad() }
 898→        updateWindowTitle()
 899→    }
