 901→    func navigatePrevious(amount: Int = 1) {
 902→        guard let folder else { return }
 903→        guard navigationThrottle.shouldProceed() else { return }
 904→        lastPrefetchDirection = .backward
 905→        if settings.dualPageEnabled {
 906→            guard amount == 1 else { return }
 907→            guard folder.goPreviousSpread() else { return }
 908→        } else {
 909→            guard folder.goPrevious(amount: amount) else { return }
 910→        }
 911→        let prevScroll: InitialScrollPosition = settings.scrollToBottomOnPrevious ? .bottom : .top
 912→        loadCurrentImage(initialScroll: prevScroll, thumbnailOnly: settings.thumbnailFallback)
 913→        if settings.thumbnailFallback { scheduleFullResLoad() }
 914→        updateWindowTitle()
