1142→    /// Pre-populate imageSizeCache with PDF page dimensions from metadata (no rendering needed).
1143→    /// This ensures SpreadManager.isWidePage() has accurate data on first build.
1144→    private func prepopulatePDFPageSizes() {
1145→        guard let folder else { return }
1146→        var pdfDocCache: [URL: CGPDFDocument] = [:]
1147→        for (index, item) in folder.images.enumerated() {
1148→            guard imageSizeCache[index] == nil,
1149→                  let pageIndex = item.pdfPageIndex else { continue }
1150→
1151→            let doc: CGPDFDocument
1152→            if let cached = pdfDocCache[item.url] {
1153→                doc = cached
1154→            } else {
1155→                guard let newDoc = CGPDFDocument(item.url as CFURL) else { continue }
1156→                pdfDocCache[item.url] = newDoc
1157→                doc = newDoc
1158→            }
1159→
1160→            // CGPDFDocument pages are 1-based
1161→            guard let page = doc.page(at: pageIndex + 1) else { continue }
1162→            let cropBox = page.getBoxRect(.cropBox)
1163→            let rotation = page.rotationAngle
1164→
1165→            let pointSize: CGSize
1166→            if rotation == 90 || rotation == 270 {
1167→                pointSize = CGSize(width: cropBox.height, height: cropBox.width)
1168→            } else {
1169→                pointSize = cropBox.size
1170→            }
1171→            imageSizeCache[index] = pointSize
1172→        }
1173→    }
