700→    /// 方向鍵根據 viewport overflow 動態切換 pan 或 navigate
701→    /// 到邊緣時需連續按 N 次才翻頁，防止瀏覽長圖時誤觸
702→    override func keyDown(with event: NSEvent) {
703→        // Continuous scroll mode: smooth scroll only, no page-turn navigation
704→        if continuousScrollEnabled {
705→            switch event.keyCode {
706→            case 124, 123:  // Left/Right Arrow — pan only when zoomed past fit-to-width
707→                if viewportOverflow.horizontal {
708→                    event.keyCode == 124 ? panRight() : panLeft()
709→                }
710→            case 125: panDown()   // Down — smooth scroll, no edge-press navigate
711→            case 126: panUp()     // Up — smooth scroll, no edge-press navigate
712→            case 49, 121:         // Space / PageDown
713→                scrollDelegate?.scrollViewRequestPageDown(self)
714→            case 116:             // PageUp
715→                scrollDelegate?.scrollViewRequestPageUp(self)
716→            case 115:             // Home
717→                scrollDelegate?.scrollViewRequestFirstImage(self)
718→            case 119:             // End
719→                scrollDelegate?.scrollViewRequestLastImage(self)
720→            case 5 where event.modifierFlags.intersection(.deviceIndependentFlagsMask) == []:
721→                scrollDelegate?.scrollViewRequestToggleQuickGrid(self)
722→            case 53:
723→                if window?.styleMask.contains(.fullScreen) == true { window?.toggleFullScreen(nil) }
724→                else { super.keyDown(with: event) }
725→            default: super.keyDown(with: event)
726→            }
727→            return
728→        }
729→
730→        let overflow = viewportOverflow
731→        let navAmount = event.modifierFlags.contains(.option) ? Constants.optionKeyJumpAmount : 1
732→
733→        switch event.keyCode {
734→        case 124: // → RightArrow
735→            let rightAction: () -> Void = { [weak self] in
736→                guard let self else { return }
737→                if self.isRTLNavigation {
738→                    self.scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
739→                } else {
740→                    self.scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
741→                }
742→            }
743→            if overflow.horizontal {
744→                if !isAtRight {
745→                    panRight()
746→                    edgePressCount = 0
747→                    hideEdgeIndicators()
748→                } else if arrowLeftRightNavigation {
749→                    handleEdgePress(keyCode: 124, navigateAction: rightAction)
750→                }
751→            } else if arrowLeftRightNavigation {
752→                resetEdgeState()
753→                rightAction()
754→            }
755→
756→        case 123: // ← LeftArrow
757→            let leftAction: () -> Void = { [weak self] in
758→                guard let self else { return }
759→                if self.isRTLNavigation {
760→                    self.scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
761→                } else {
762→                    self.scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
763→                }
764→            }
765→            if overflow.horizontal {
766→                if !isAtLeft {
767→                    panLeft()
768→                    edgePressCount = 0
769→                    hideEdgeIndicators()
770→                } else if arrowLeftRightNavigation {
771→                    handleEdgePress(keyCode: 123, navigateAction: leftAction)
772→                }
773→            } else if arrowLeftRightNavigation {
774→                resetEdgeState()
775→                leftAction()
776→            }
777→
778→        case 125: // ↓ DownArrow
779→            if overflow.vertical && !isAtBottom {
780→                panDown()
781→                edgePressCount = 0
782→                hideEdgeIndicators()
783→            } else if arrowUpDownNavigation {
784→                if overflow.vertical {
785→                    // At bottom edge: edge-press to navigate
786→                    handleEdgePress(keyCode: 125) { [weak self] in
787→                        guard let self else { return }
788→                        self.scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
789→                    }
790→                } else {
791→                    // No vertical overflow: navigate directly
792→                    resetEdgeState()
793→                    scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
794→                }
795→            }
796→
797→        case 126: // ↑ UpArrow
798→            if overflow.vertical && !isAtTop {
799→                panUp()
800→                edgePressCount = 0
801→                hideEdgeIndicators()
802→            } else if arrowUpDownNavigation {
803→                if overflow.vertical {
804→                    // At top edge: edge-press to navigate
805→                    handleEdgePress(keyCode: 126) { [weak self] in
806→                        guard let self else { return }
807→                        self.scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
808→                    }
809→                } else {
810→                    // No vertical overflow: navigate directly
811→                    resetEdgeState()
812→                    scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
813→                }
814→            }
815→
816→        case 49, 121: // Space / PageDown
817→            if overflow.vertical && isAtBottom {
818→                handleEdgePress(keyCode: event.keyCode, threshold: 1) { [weak self] in
819→                    guard let self else { return }
820→                    scrollDelegate?.scrollViewRequestPageDown(self)
821→                }
822→            } else {
823→                edgePressCount = 0
824→                hideEdgeIndicators()
825→                scrollDelegate?.scrollViewRequestPageDown(self)
826→            }
827→
828→        case 116: // PageUp
829→            if overflow.vertical && isAtTop {
830→                handleEdgePress(keyCode: 116, threshold: 1) { [weak self] in
831→                    guard let self else { return }
832→                    scrollDelegate?.scrollViewRequestPageUp(self)
833→                }
834→            } else {
835→                edgePressCount = 0
836→                hideEdgeIndicators()
837→                scrollDelegate?.scrollViewRequestPageUp(self)
838→            }
839→
840→        case 115: scrollDelegate?.scrollViewRequestFirstImage(self)     // Home
841→        case 119: scrollDelegate?.scrollViewRequestLastImage(self)      // End
842→        case 5 where event.modifierFlags.intersection(.deviceIndependentFlagsMask) == []:  // bare G (no modifiers)
843→            scrollDelegate?.scrollViewRequestToggleQuickGrid(self)
844→        case 53:  // Esc — 退出全螢幕（僅在全螢幕模式下有效）
845→            if window?.styleMask.contains(.fullScreen) == true {
846→                window?.toggleFullScreen(nil)
847→            } else {
848→                super.keyDown(with: event)
849→            }
850→        default:  super.keyDown(with: event)
851→        }
852→    }
