854→    // MARK: - Three-Finger Pan (raw touch tracking)
855→
856→    override func touchesBegan(with event: NSEvent) {
857→        let touches = event.touches(matching: .touching, in: self)
858→        if touches.count == 3 {
859→            threeFingerPanActive = true
860→            previousTouchPositions.removeAll()
861→            for touch in touches {
862→                guard let key = touch.identity as? NSObject else { continue }
863→                previousTouchPositions[key] = touch.normalizedPosition
864→            }
865→        } else {
866→            super.touchesBegan(with: event)
867→        }
868→    }
869→
870→    override func touchesMoved(with event: NSEvent) {
871→        let touches = event.touches(matching: .touching, in: self)
872→
873→        guard touches.count == 3, threeFingerPanActive else {
874→            if !threeFingerPanActive {
875→                super.touchesMoved(with: event)
876→            }
877→            return
878→        }
879→
880→        var totalDeltaX: CGFloat = 0
881→        var totalDeltaY: CGFloat = 0
882→        var matchedCount = 0
883→
884→        // Map normalized trackpad movement to viewport size for drag-like feel:
885→        // full trackpad swipe = full viewport scroll
886→        let viewportSize = contentView.bounds.size
887→
888→        for touch in touches {
889→            guard let key = touch.identity as? NSObject else { continue }
890→            let currentPos = touch.normalizedPosition
891→            if let prevPos = previousTouchPositions[key] {
892→                totalDeltaX += (currentPos.x - prevPos.x) * viewportSize.width
893→                totalDeltaY += (currentPos.y - prevPos.y) * viewportSize.height
894→                matchedCount += 1
895→            }
896→            previousTouchPositions[key] = currentPos
897→        }
898→
899→        guard matchedCount > 0 else { return }
900→        let avgDeltaX = totalDeltaX / CGFloat(matchedCount)
901→        let avgDeltaY = totalDeltaY / CGFloat(matchedCount)
902→        performPan(deltaX: avgDeltaX, deltaY: avgDeltaY)
903→    }
904→
905→    override func touchesEnded(with event: NSEvent) {
906→        let remaining = event.touches(matching: .touching, in: self)
907→        if remaining.count < 3 {
908→            resetThreeFingerPanState()
909→        }
910→        super.touchesEnded(with: event)
911→    }
912→
913→    override func touchesCancelled(with event: NSEvent) {
914→        resetThreeFingerPanState()
915→        super.touchesCancelled(with: event)
916→    }
