918→    /// Shared pan helper for mouse drag and three-finger trackpad pan.
919→    /// Moves the clip view origin by the given delta (in view coordinates).
920→    private func performPan(deltaX: CGFloat, deltaY: CGFloat) {
921→        let clip = contentView
922→        guard let docView = documentView else { return }
923→
924→        let docSize = docView.frame.size
925→        let clipSize = clip.bounds.size
926→
927→        // 手指右移(+deltaX) → 內容左移 → origin.x 減少
928→        // 手指上移(+deltaY) → 內容下移 → origin.y 減少 (unflipped: y=0 at bottom)
929→        var newX = clip.bounds.origin.x - deltaX
930→        var newY = clip.bounds.origin.y - deltaY
931→
932→        let insets = contentInsets
933→        newX = max(-insets.left, min(newX, docSize.width - clipSize.width + insets.right))
934→        let yBounds = yScrollBounds(docHeight: docSize.height, clipHeight: clipSize.height, insets: insets)
935→        newY = max(yBounds.min, min(newY, yBounds.max))
936→
937→        clip.scroll(to: NSPoint(x: newX, y: newY))
938→        reflectScrolledClipView(clip)
939→    }
