948→    private func handleCmdScrollZoom(with event: NSEvent) {
949→        let delta = event.scrollingDeltaY
950→        guard abs(delta) > 0.01 else { return }
951→
952→        // Zoom 方向：deltaY > 0 = 放大，deltaY < 0 = 縮小
953→        // 不跟隨 Natural Scrolling 反轉（主流慣例：scroll up = zoom in）
954→        let sensitivity: CGFloat = event.hasPreciseScrollingDeltas ? 0.003 : 0.08
955→        let newMag = magnification + delta * sensitivity
956→        let effectiveMin = effectiveMinMagnification()
957→        let clamped = max(effectiveMin, min(maxMagnification, newMag))
958→
959→        // 以可預測的視窗中心為 anchor（避免 contentInsets 暫時被重置時漂移到左側）
960→        let center = zoomAnchorPoint()
961→        setMagnificationPreservingInsets(clamped, centeredAt: center)
962→
963→        // 通知 delegate（與 pinch zoom 一致）
964→        scrollDelegate?.scrollViewMagnificationDidChange(
965→            self, magnification: magnification, gesturePhase: event.phase
966→        )
967→    }
