969→    // MARK: - Option + Scroll Fast Navigation (Phase 3)
970→
971→    private func handleOptionScrollNav(with event: NSEvent) {
972→        let isTrackpad = event.phase != [] || event.momentumPhase != []
973→        let isMomentum = event.momentumPhase != []
974→
975→        // Trackpad: 新手勢開始時重置累積器
976→        if event.phase == .began {
977→            optionScrollAccumulator.resetForNewGesture()
978→            resetEdgeState()
979→        }
980→
981→        // Mouse: 沒有 .began phase，改用時間間隔偵測新手勢
982→        if !isTrackpad {
983→            let now = CFAbsoluteTimeGetCurrent()
984→            if now - lastOptionScrollTime > Constants.optionScrollMouseResetInterval {
985→                optionScrollAccumulator.resetForNewGesture()
986→                resetEdgeState()
987→            }
988→            lastOptionScrollTime = now
989→        }
990→
991→        // Natural Scrolling 方向校正（與 page-turn 邏輯一致）
992→        let isNatural = event.isDirectionInvertedFromDevice
993→        let rawDelta = event.scrollingDeltaY
994→        let correctedDelta: CGFloat
995→        if isNatural {
996→            correctedDelta = -rawDelta
997→        } else {
998→            correctedDelta = rawDelta
999→        }

